// Resolve a COMPUTE_MAP module path (relative to this file) and import it.
// Lets consumers at any directory depth (test/unit, scripts/) reuse the
// map's relative paths without rewriting them.
export function importCalc(relModule) {
  return import(new URL(relModule, import.meta.url));
}
